package com.socialblog.follower.api;import com.socialblog.follower.domain.*;import com.socialblog.follower.repository.*;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.test.web.servlet.MockMvc;import java.util.UUID;import static org.assertj.core.api.Assertions.assertThat;import static org.springframework.security.test.web.servlet.request.SecurityMockMvcRequestPostProcessors.jwt;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@SpringBootTest @AutoConfigureMockMvc class FollowControllerIntegrationTest{@Autowired MockMvc mvc;@Autowired UserProjectionRepository users;@Autowired OutboxEventRepository outbox;@Test void followUnfollowAreIdempotentAndListsArePublic()throws Exception{UUID actor=UUID.randomUUID(),target=UUID.randomUUID();users.save(new UserProjection(actor,true,"Actor"));users.save(new UserProjection(target,true,"Target"));String path="/api/v1/follows/"+target;mvc.perform(put(path).header("X-Correlation-ID","follow-correlation").with(jwt().jwt(j->j.subject(actor.toString())))).andExpect(status().isOk()).andExpect(jsonPath("$.following").value(true)).andExpect(jsonPath("$.followerCount").value(1));mvc.perform(put(path).with(jwt().jwt(j->j.subject(actor.toString())))).andExpect(status().isOk()).andExpect(jsonPath("$.followerCount").value(1));assertThat(outbox.findAll().stream().filter(e->e.getPayload().contains("UserFollowed")).count()).isEqualTo(1);assertThat(outbox.findAll()).anySatisfy(e->assertThat(e.getPayload()).contains("follow-correlation"));mvc.perform(get("/api/v1/follows/users/"+target+"/followers")).andExpect(status().isOk()).andExpect(jsonPath("$.content[0].userId").value(actor.toString())).andExpect(jsonPath("$.content[0].displayName").value("Actor"));mvc.perform(get("/api/v1/follows/status/"+target).with(jwt().jwt(j->j.subject(actor.toString())))).andExpect(status().isOk()).andExpect(jsonPath("$.following").value(true));mvc.perform(delete(path).with(jwt().jwt(j->j.subject(actor.toString())))).andExpect(status().isOk()).andExpect(jsonPath("$.following").value(false));mvc.perform(delete(path).with(jwt().jwt(j->j.subject(actor.toString())))).andExpect(status().isOk());assertThat(outbox.findAll().stream().filter(e->e.getPayload().contains("UserUnfollowed")).count()).isEqualTo(1);}@Test void rejectsSelfAndUnavailableFollow()throws Exception{UUID user=UUID.randomUUID();mvc.perform(put("/api/v1/follows/"+user).with(jwt().jwt(j->j.subject(user.toString())))).andExpect(status().isBadRequest()).andExpect(jsonPath("$.code").value("SELF_FOLLOW_NOT_ALLOWED"));mvc.perform(put("/api/v1/follows/"+UUID.randomUUID()).with(jwt().jwt(j->j.subject(user.toString())))).andExpect(status().isConflict()).andExpect(jsonPath("$.code").value("USER_NOT_AVAILABLE"));}@Test void mutationRequiresAuthentication()throws Exception{mvc.perform(put("/api/v1/follows/"+UUID.randomUUID())).andExpect(status().isUnauthorized());}@Test void standardizesListParameterErrors()throws Exception{UUID user=UUID.randomUUID();mvc.perform(get("/api/v1/follows/users/"+user+"/followers?page=-1")).andExpect(status().isBadRequest()).andExpect(jsonPath("$.code").value("INVALID_PAGE")).andExpect(jsonPath("$.path").value("/api/v1/follows/users/"+user+"/followers"));mvc.perform(get("/api/v1/follows/users/not-a-uuid/followers")).andExpect(status().isBadRequest()).andExpect(jsonPath("$.code").value("INVALID_REQUEST_PARAMETER")).andExpect(jsonPath("$.fields.id").isNotEmpty());}}
